// Fall back to payload.auth() for cases where middleware hasn't run.
let user = req.user
if (!user) {
  const authResult = await req.payload.auth({ headers: req.headers })
  user = authResult.user
}

if (!user) {
  // Check for guest session
  const guestToken = getGuestSessionCookie(req.headers as unknown as Headers)
  if (guestToken) {
    guestSession = await getGuestSessionByToken(req.payload, guestToken)
  }

import type { User } from '@/payload-types'

export function isUsersCollectionUser(user: unknown): user is User & { collection?: 'users' } {
  if (!user || typeof user !== 'object') {
    return false
  }

  const candidate = user as { id?: unknown; collection?: unknown }
  if (candidate.id === undefined || candidate.id === null) {
    return false
  }

  if ('collection' in candidate && candidate.collection !== 'users') {
    return false
  }

  return true
}

