  if (!result.success) {
    reqLogger.error({ error: result.error, modelLatencyMs }, 'Chat request failed')
    return jsonWithCookie(
      { error: result.error || 'Failed to process chat message' },
      { status: 500, cookieHeader: guestCookieHeader },
    )
  }

